import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { ChevronLeft, ChevronRight, Download } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import type { Officer, Beat, Shift } from "@/lib/types";

export default function Schedule() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [view, setView] = useState("week");

  const { data: officers } = useQuery<Officer[]>({
    queryKey: ["/api/officers"],
  });

  const { data: beats } = useQuery<Beat[]>({
    queryKey: ["/api/beats"],
  });

  const { data: shifts } = useQuery<Shift[]>({
    queryKey: ["/api/shifts"],
  });

  const getWeekDates = (date: Date) => {
    const week = [];
    const startOfWeek = new Date(date);
    const day = startOfWeek.getDay();
    const diff = startOfWeek.getDate() - day + (day === 0 ? -6 : 1);
    startOfWeek.setDate(diff);

    for (let i = 0; i < 7; i++) {
      const weekDate = new Date(startOfWeek);
      weekDate.setDate(startOfWeek.getDate() + i);
      week.push(weekDate);
    }
    return week;
  };

  const weekDates = getWeekDates(currentDate);
  const weekStart = weekDates[0];
  const weekEnd = weekDates[6];

  // Simplified view for 2 shifts: Diurno (7am-6pm) and Nocturno (6pm-7am)
  const shiftSlots = [
    { 
      name: "Turno Diurno", 
      time: "07:00 - 18:00", 
      type: "diurno",
      startHour: 7,
      endHour: 18 
    },
    { 
      name: "Turno Nocturno", 
      time: "18:00 - 07:00", 
      type: "nocturno",
      startHour: 18,
      endHour: 7 
    }
  ];

  const previousWeek = () => {
    const newDate = new Date(currentDate);
    newDate.setDate(currentDate.getDate() - 7);
    setCurrentDate(newDate);
  };

  const nextWeek = () => {
    const newDate = new Date(currentDate);
    newDate.setDate(currentDate.getDate() + 7);
    setCurrentDate(newDate);
  };

  const getShiftForTimeAndDate = (time: string, date: Date) => {
    const dateStr = date.toISOString().split('T')[0];
    const timeNum = parseInt(time.split(':')[0]);

    return shifts?.find(shift => {
      if (shift.date !== dateStr) return false;

      const startTime = parseInt(shift.startTime.split(':')[0]);
      const endTime = parseInt(shift.endTime.split(':')[0]);

      // Handle overnight shifts
      if (startTime > endTime) {
        return timeNum >= startTime || timeNum < endTime;
      } else {
        return timeNum >= startTime && timeNum < endTime;
      }
    });
  };

  const getOfficerName = (officerId?: string) => {
    if (!officerId) return "Sin asignar";
    const officer = officers?.find(o => o.id === officerId);
    return officer ? officer.name.split(' ').pop() : "Desconocido";
  };

  const getShiftColor = (shift: Shift | undefined, officerId?: string) => {
    if (!shift) return "bg-gray-50";
    if (!officerId) return "bg-red-100 text-red-800";

    const colors = [
      "bg-green-100 text-green-800",
      "bg-blue-100 text-blue-800",
      "bg-purple-100 text-purple-800",
      "bg-yellow-100 text-yellow-800",
      "bg-pink-100 text-pink-800",
      "bg-indigo-100 text-indigo-800"
    ];

    const hash = (officerId || '').split('').reduce((a, b) => {
      a = ((a << 5) - a) + b.charCodeAt(0);
      return a & a;
    }, 0);

    return colors[Math.abs(hash) % colors.length];
  };

  const formatWeekRange = () => {
    const options: Intl.DateTimeFormatOptions = { month: 'long', day: 'numeric' };
    const startStr = weekStart.toLocaleDateString('en-US', options);
    const endStr = weekEnd.toLocaleDateString('en-US', options);
    const year = weekStart.getFullYear();
    return `Week of ${startStr} - ${endStr}, ${year}`;
  };

  return (
    <div className="h-full overflow-auto">
      <div className="p-6 space-y-6">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h2 className="text-2xl font-bold text-gray-900">Gestión de Horarios</h2>
            <p className="text-gray-600 mt-1">Ver y gestionar asignaciones de turnos</p>
          </div>
          <div className="mt-4 sm:mt-0 flex space-x-3">
            <Select value={view} onValueChange={setView}>
              <SelectTrigger className="w-40" data-testid="select-view">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="week">Vista Semanal</SelectItem>
                <SelectItem value="month">Vista Mensual</SelectItem>
              </SelectContent>
            </Select>
            <Button variant="outline" data-testid="button-export">
              <Download className="w-4 h-4 mr-2" />
              Exportar
            </Button>
          </div>
        </div>

        {/* Calendar Grid */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="px-6 py-4 bg-gray-50 border-b border-gray-200">
            <div className="flex items-center justify-between">
              <h3 className="text-lg font-semibold text-gray-900">{formatWeekRange()}</h3>
              <div className="flex space-x-2">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={previousWeek}
                  data-testid="button-previous-week"
                >
                  <ChevronLeft className="h-4 w-4" />
                </Button>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={nextWeek}
                  data-testid="button-next-week"
                >
                  <ChevronRight className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </div>

          {/* Calendar Header */}
          <div className="grid grid-cols-8 border-b border-gray-200">
            <div className="p-4 bg-gray-50 text-sm font-medium text-gray-900">Turno</div>
            {weekDates.map((date, index) => (
              <div key={index} className="p-4 bg-gray-50 text-sm font-medium text-gray-900 text-center">
                <div>{['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'][index]}</div>
                <div className="text-xs text-gray-500">{date.getDate()}</div>
              </div>
            ))}
          </div>

          {/* Calendar Body - Simplified for 2 shifts */}
          <div className="divide-y divide-gray-200">
            {shiftSlots.map((slot) => (
              <div key={slot.type} className="grid grid-cols-8 min-h-20">
                <div className="p-4 bg-gray-50 text-sm text-gray-600 font-medium border-r border-gray-200">
                  <div className="font-semibold">{slot.name}</div>
                  <div className="text-xs text-gray-500">{slot.time}</div>
                </div>
                {weekDates.map((date, index) => {
                  const dateStr = date.toISOString().split('T')[0];
                  const shift = shifts?.find(s => s.date === dateStr && s.shiftType === slot.type);
                  const officerName = getOfficerName(shift?.officerId || undefined);
                  const colorClass = getShiftColor(shift, shift?.officerId || undefined);

                  return (
                    <div key={index} className="p-2 border-r border-gray-200">
                      {shift ? (
                        <div 
                          className={`text-xs px-2 py-1 rounded font-medium ${colorClass}`}
                          data-testid={`shift-${shift.id}`}
                        >
                          {officerName}
                        </div>
                      ) : (
                        <div className="text-xs px-2 py-1 rounded bg-gray-100 text-gray-500">
                          Disponible
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

